css:
.print-heading {
    text-align: center;
    margin-bottom: 24px;
}

.print-heading h2 {
    margin: 0;
    font-size: 18pt;
}

.print-heading p {
    margin: 6px 0 0;
}

.document-purpose {
    margin: 0 0 24px;
    padding: 12px 14px;
    border: 1px solid #d8d8d8;
    border-left: 4px solid #b40000;
    border-radius: 6px;
    background: #fafafa;
    line-height: 1.45;
}

.document-purpose strong {
    display: block;
    margin-bottom: 6px;
    font-size: 11pt;
}

.document-purpose p {
    margin: 0 0 7px;
}

.document-purpose p:last-child {
    margin-bottom: 0;
}

.section-heading {
    margin-top: 22px;
    margin-bottom: 10px;
    padding-bottom: 5px;
    border-bottom: 1px solid #b40000;
    font-size: 12pt;
    font-weight: 600;
    page-break-after: avoid;
}

.summary-table {
    width: 100%;
    margin-bottom: 20px;
    border: 1px solid #ddd;
    border-spacing: 0;
    border-collapse: separate;
    border-radius: 8px;
    overflow: hidden;
}

.summary-table th,
.summary-table td {
    padding: 8px;
    vertical-align: top;
}

.summary-table th {
    background-color: #f5f5f5;
    border-right: 1px solid #ddd;
    border-bottom: 1px solid #ddd;
    font-weight: 600;
    text-align: left;
}

.summary-table td {
    border-right: 1px solid #ddd;
    border-bottom: 1px solid #ddd;
}

.summary-table th:last-child,
.summary-table td:last-child {
    border-right: none;
}

.summary-table tbody tr:last-child td,
.summary-table tbody tr:last-child th {
    border-bottom: none;
}

.summary-table tbody tr:nth-child(odd) td {
    background-color: #fafafa;
}

.summary-table tr {
    page-break-inside: avoid;
}

.details-table {
    table-layout: fixed;
}

.details-table th {
    width: 17%;
}

.details-table td {
    width: 33%;
}

.secondary-value {
    display: block;
    margin-top: 2px;
    color: #666;
    font-size: 9pt;
}

.number-column {
    width: 36px;
    text-align: center !important;
}

.code-column {
    width: 58px;
    white-space: nowrap;
    text-align: center !important;
}

.date-column {
    width: 105px;
    white-space: nowrap;
}

.datetime-column {
    width: 122px;
    white-space: nowrap;
}

.occurrence-column {
    width: 105px;
}

.sanction-column {
    width: 145px;
}

.status-column {
    width: 82px;
    white-space: nowrap;
}

.action-column {
    width: 105px;
    white-space: nowrap;
}

.empty-row {
    color: #777;
    font-style: italic;
    text-align: center;
}

.empty-inline {
    color: #777;
    font-style: italic;
}

.preserve-lines {
    white-space: pre-line;
}

.outcome-summary {
    margin-bottom: 8px;
    padding: 15px 16px;
    border: 1px solid #d6d6d6;
    border-left: 5px solid #b40000;
    border-radius: 8px;
    background: #fafafa;
    page-break-inside: avoid;
}

.outcome-summary-label {
    margin-bottom: 5px;
    color: #555;
    font-size: 9.5pt;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.outcome-summary-value {
    margin-bottom: 5px;
    font-size: 15pt;
    font-weight: 700;
}

.outcome-summary-context {
    color: #555;
    font-size: 9.5pt;
}

.outcome-unconfigured {
    color: #666;
    font-size: 12pt;
}

.outcome-disclaimer {
    margin-bottom: 20px;
    padding: 9px 11px;
    border-radius: 5px;
    background: #f5f5f5;
    color: #555;
    font-size: 9pt;
    line-height: 1.4;
    page-break-inside: avoid;
}

.history-information-note {
    margin: 0 0 10px;
    padding: 9px 11px;
    border: 1px solid #ddd;
    border-left: 4px solid #777;
    border-radius: 5px;
    background: #fafafa;
    color: #555;
    font-size: 9pt;
    line-height: 1.4;
    page-break-inside: avoid;
}

.history-status {
    display: inline-block;
    padding: 3px 7px;
    border: 1px solid #ccc;
    border-radius: 10px;
    font-size: 8.5pt;
    font-weight: 600;
    white-space: nowrap;
}

.history-status-pending {
    background: #fff7e6;
    border-color: #d8b56c;
}

.history-status-cancelled {
    background: #f1f1f1;
    border-color: #bbb;
    color: #666;
}

.confirmation-text {
    line-height: 1.45;
    page-break-inside: avoid;
}

.confirmation-text p {
    margin: 0 0 9px;
}

.decision-boxes {
    margin: 16px 0;
    padding: 8px 12px;
    border: 1px solid #ddd;
    border-radius: 8px;
    page-break-inside: avoid;
}

.decision-boxes table {
    width: 100%;
    border-collapse: collapse;
}

.decision-boxes td {
    padding: 6px 0;
    border: none;
    vertical-align: top;
}

.decision-boxes .check-cell {
    width: 28px;
    font-size: 14pt;
}

.comments-box {
    margin-top: 16px;
    page-break-inside: avoid;
}

.comments-label {
    margin-bottom: 12px;
    font-weight: 600;
}

.writing-line {
    height: 26px;
    border-bottom: 1px solid #777;
}

.signatures {
    margin-top: 24px;
    page-break-inside: auto;
}

.signatures table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
}

.signatures tr {
    page-break-inside: avoid;
}

.signatures td {
    border: none;
    vertical-align: bottom;
}

.signatures .signature-cell {
    width: 68%;
    padding: 38px 30px 16px 0;
}

.signatures .date-cell {
    width: 32%;
    padding: 38px 0 16px 20px;
}

.signatures .signature-line {
    min-height: 22px;
    border-bottom: 1px solid #222;
}

.signatures .signature-label {
    margin-top: 5px;
    font-size: 10.5pt;
    line-height: 1.3;
}

@page {
    @bottom-right {
        content: "Page " counter(page) " of " counter(pages);
        font-size: 10pt;
        color: #999;
    }
}

format_data:
[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div class="print-heading">
    <h2>Disciplinary Action Management Summary</h2>
    <p>{{ doc.name }}</p>

    {% if doc.request_date %}
        <p>
            Request recorded:
            {{ frappe.utils.format_datetime(doc.request_date, "dd MMMM yyyy, HH:mm") }}
        </p>
    {% endif %}
</div>

<div class="document-purpose">
    <strong>Purpose of this document</strong>

    <p>
        This summary records the information supplied in support of a request
        for disciplinary action. It is provided to the person initiating the
        request so that the details may be reviewed and confirmed before the
        matter proceeds to the next appropriate step.
    </p>

    <p>
        Any sanction shown below is a policy guideline only. It does not
        constitute a finding of guilt, a predetermined outcome, or a final
        disciplinary sanction.
    </p>
</div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "{# ============================================================
   BASIC VARIABLES
   ============================================================ #}

{% set offence_rows = doc.offences or [] %}
{% set charge_rows = doc.final_charges or [] %}
{% set history_rows = doc.previous_disciplinary_outcomes or [] %}


{# ============================================================
   DETERMINE THE HARSHEST APPLICABLE SANCTION

   Repeat-offence progression is based only on:
   - the same employee;
   - the same exact Disciplinary Offence code;
   - a previous Disciplinary Action with an outcome;
   - a previous action that is not cancelled;
   - a previous outcome that is not a cancellation.
   ============================================================ #}

{% set sanction_results = [] %}

{% set highest = namespace(
    rank=-1,
    outcome="",
    code_item="",
    occurrence=0
) %}

{% for offence in offence_rows %}
    {% if offence.code_item %}

        {% set previous_count = namespace(value=0) %}

        {% set previous_actions = frappe.get_all(
            "Disciplinary Action",
            filters={
                "accused": doc.accused,
                "name": ["!=", doc.name],
                "docstatus": ["!=", 2],
                "outcome": ["is", "set"]
            },
            fields=["name", "outcome"]
        ) %}

        {% for previous_action in previous_actions %}
            {% set action_state = namespace(include=true) %}

            {% if previous_action.outcome %}
                {% set is_cancellation = frappe.db.get_value(
                    "Offence Outcome",
                    previous_action.outcome,
                    "iscancellation"
                ) or 0 %}

                {% if is_cancellation %}
                    {% set action_state.include = false %}
                {% endif %}
            {% endif %}

            {% if action_state.include %}
                {% set matching_charges = frappe.get_all(
                    "Disciplinary Charges",
                    filters={
                        "parent": previous_action.name,
                        "parenttype": "Disciplinary Action",
                        "parentfield": "final_charges",
                        "code_item": offence.code_item
                    },
                    fields=["name"]
                ) %}

                {% set previous_count.value =
                    previous_count.value + (matching_charges | length)
                %}
            {% endif %}
        {% endfor %}

        {% set occurrence = previous_count.value + 1 %}

        {% if occurrence <= 1 %}
            {% set sanction_field = "sanction_on_first_offence" %}
        {% elif occurrence == 2 %}
            {% set sanction_field = "sanction_on_second_offence" %}
        {% elif occurrence == 3 %}
            {% set sanction_field = "sanction_on_third_offence" %}
        {% else %}
            {% set sanction_field = "sanction_on_fourth_offence" %}
        {% endif %}

        {% set offence_details = frappe.db.get_value(
            "Disciplinary Offence",
            offence.code_item,
            [
                "offence_description",
                sanction_field
            ],
            as_dict=True
        ) or {} %}

        {% set applicable_outcome =
            offence_details.get(sanction_field) or ""
        %}

        {% set outcome_details = {} %}

        {% if applicable_outcome %}
            {% set outcome_details = frappe.db.get_value(
                "Offence Outcome",
                applicable_outcome,
                [
                    "disc_offence_out",
                    "severity_rank"
                ],
                as_dict=True
            ) or {} %}
        {% endif %}

        {% set outcome_label =
            outcome_details.disc_offence_out
            or applicable_outcome
            or "No sanction configured"
        %}

        {% set outcome_rank =
            outcome_details.severity_rank or 0
        %}

        {% set result = {
            "code_item": offence.code_item,
            "description": offence_details.offence_description
                or offence.code_item,
            "occurrence": occurrence,
            "outcome": outcome_label,
            "rank": outcome_rank
        } %}

        {% set _ = sanction_results.append(result) %}

        {% if applicable_outcome and outcome_rank > highest.rank %}
            {% set highest.rank = outcome_rank %}
            {% set highest.outcome = outcome_label %}
            {% set highest.code_item = offence.code_item %}
            {% set highest.occurrence = occurrence %}
        {% endif %}

    {% endif %}
{% endfor %}


{# ============================================================
   EMPLOYEE DETAILS
   ============================================================ #}

<h4 class="section-heading">Employee concerned</h4>

<table class="summary-table details-table">
    <tbody>
        <tr>
            <th>Employee</th>

            <td>
                {{ doc.accused_name or "" }}

                {% if doc.accused %}
                    <span class="secondary-value">
                        {{ doc.accused }}
                    </span>
                {% endif %}
            </td>

            <th>Position</th>

            <td>
                {{ doc.accused_pos or "" }}
            </td>
        </tr>

        <tr>
            <th>Company number</th>

            <td>
                {{ doc.accused_coy or "" }}
            </td>

            <th>Site for hearing</th>

            <td>
                {{ doc.branch or "" }}
            </td>
        </tr>

        <tr>
            <th>Date engaged</th>

            <td>
                {% if doc.engagement_date %}
                    {{ frappe.utils.formatdate(
                        doc.engagement_date,
                        "dd MMMM yyyy"
                    ) }}
                {% else %}
                    —
                {% endif %}
            </td>

            <th>Shop Steward</th>

            <td>
                {% if doc.is_ss %}
                    Yes

                    {% if doc.ss_union %}
                        — {{ doc.ss_union }}
                    {% endif %}
                {% else %}
                    No
                {% endif %}
            </td>
        </tr>
    </tbody>
</table>


{# ============================================================
   PERSON INITIATING THE ACTION
   ============================================================ #}

<h4 class="section-heading">
    Person initiating disciplinary action
</h4>

<table class="summary-table details-table">
    <tbody>
        <tr>
            <th>Name</th>

            <td>
                {{ doc.compl_name or "" }}

                {% if doc.complainant %}
                    <span class="secondary-value">
                        {{ doc.complainant }}
                    </span>
                {% endif %}
            </td>

            <th>Position</th>

            <td>
                {{ doc.compl_pos or "" }}
            </td>
        </tr>

        <tr>
            <th>Request date</th>

            <td>
                {% if doc.request_date %}
                    {{ frappe.utils.format_datetime(
                        doc.request_date,
                        "dd MMMM yyyy, HH:mm"
                    ) }}
                {% else %}
                    —
                {% endif %}
            </td>

            <th>Responsible IR</th>

            <td>
                {{ doc.responsible_ir_name
                    or doc.responsible_ir
                    or "Not yet assigned"
                }}

                {% if doc.responsible_ir_no %}
                    <span class="secondary-value">
                        {{ doc.responsible_ir_no }}
                    </span>
                {% endif %}
            </td>
        </tr>
    </tbody>
</table>


{# ============================================================
   INCIDENTS REPORTED
   ============================================================ #}

<h4 class="section-heading">
    Reported offence(s) and incident details
</h4>

<table class="summary-table offence-table">
    <thead>
        <tr>
            <th class="number-column">No.</th>
            <th class="code-column">Code</th>
            <th>Offence</th>
            <th class="datetime-column">Date and time</th>
            <th>Incident details</th>
        </tr>
    </thead>

    <tbody>
        {% if offence_rows %}
            {% for row in offence_rows %}
                <tr>
                    <td class="number-column">
                        {{ row.idx }}
                    </td>

                    <td class="code-column">
                        {{ row.offence_code or row.code_item or "" }}
                    </td>

                    <td>
                        {% if row.code_item %}
                            {{ frappe.db.get_value(
                                "Disciplinary Offence",
                                row.code_item,
                                "offence_description"
                            ) or row.code_item }}
                        {% endif %}
                    </td>

                    <td class="datetime-column">
                        {% if row.offence_datetime %}
                            {{ frappe.utils.format_datetime(
                                row.offence_datetime,
                                "dd MMM yyyy, HH:mm"
                            ) }}
                        {% endif %}
                    </td>

                    <td>
                        {{ row.incident_details or "" }}
                    </td>
                </tr>
            {% endfor %}
        {% else %}
            <tr>
                <td colspan="5" class="empty-row">
                    No offences have been recorded.
                </td>
            </tr>
        {% endif %}
    </tbody>
</table>


{# ============================================================
   PROPOSED CHARGES
   ============================================================ #}

<h4 class="section-heading">
    Proposed charge(s)
</h4>

<table class="summary-table">
    <thead>
        <tr>
            <th class="number-column">No.</th>
            <th class="code-column">Code</th>
            <th>Proposed charge</th>
        </tr>
    </thead>

    <tbody>
        {% if charge_rows %}
            {% for row in charge_rows %}
                <tr>
                    <td class="number-column">
                        {{ row.idx }}
                    </td>

                    <td class="code-column">
                        {{ row.code_item or "" }}
                    </td>

                    <td>
                        {{ row.charge or "" }}
                    </td>
                </tr>
            {% endfor %}
        {% else %}
            <tr>
                <td colspan="3" class="empty-row">
                    No proposed charges have been recorded.
                </td>
            </tr>
        {% endif %}
    </tbody>
</table>


{# ============================================================
   APPLICABLE SANCTION GUIDELINE
   ============================================================ #}

<h4 class="section-heading">
    Applicable sanction guideline
</h4>

<div class="outcome-summary">
    {% if highest.outcome %}
        <div class="outcome-summary-label">
            Harshest currently applicable guideline
        </div>

        <div class="outcome-summary-value">
            {{ highest.outcome }}
        </div>

        <div class="outcome-summary-context">
            Based on offence code
            <strong>{{ highest.code_item }}</strong>
            and its currently calculated

            {% if highest.occurrence == 1 %}
                first
            {% elif highest.occurrence == 2 %}
                second
            {% elif highest.occurrence == 3 %}
                third
            {% else %}
                fourth or subsequent
            {% endif %}

            occurrence.
        </div>

    {% elif offence_rows %}
        <div class="outcome-summary-label">
            Harshest currently applicable guideline
        </div>

        <div class="outcome-summary-value outcome-unconfigured">
            No ranked sanction could be determined
        </div>

        <div class="outcome-summary-context">
            Confirm that the selected Disciplinary Offence records
            have applicable sanctions and that the linked Offence
            Outcomes have severity ranks.
        </div>

    {% else %}
        <div class="outcome-summary-value outcome-unconfigured">
            No offence has been selected.
        </div>
    {% endif %}
</div>

<div class="outcome-disclaimer">
    <strong>Important:</strong>

    This is an indicative policy guideline generated from the
    offence code, prior recorded occurrences and configured sanction
    rankings. It does not predetermine guilt or bind the chairperson,
    initiator, employee or Company to a particular outcome.
</div>


{# ============================================================
   SANCTION DETAIL TABLE
   ============================================================ #}

{% if sanction_results %}
    <table class="summary-table sanction-detail-table">
        <thead>
            <tr>
                <th class="code-column">Code</th>
                <th>Offence</th>
                <th class="occurrence-column">Occurrence</th>
                <th class="sanction-column">
                    Applicable guideline
                </th>
            </tr>
        </thead>

        <tbody>
            {% for result in sanction_results %}
                <tr>
                    <td class="code-column">
                        {{ result.code_item }}
                    </td>

                    <td>
                        {{ result.description }}
                    </td>

                    <td class="occurrence-column">
                        {% if result.occurrence == 1 %}
                            First
                        {% elif result.occurrence == 2 %}
                            Second
                        {% elif result.occurrence == 3 %}
                            Third
                        {% else %}
                            Fourth or subsequent
                        {% endif %}
                    </td>

                    <td class="sanction-column">
                        {{ result.outcome }}
                    </td>
                </tr>
            {% endfor %}
        </tbody>
    </table>
{% endif %}


{# ============================================================
   TRACKED / CONCLUDED DISCIPLINARY HISTORY

   This displays the employee's broader concluded disciplinary
   history. Only exact matching offence codes are used for the
   repeat-offence escalation calculation above.
   ============================================================ #}

{% if history_rows %}
    <h4 class="section-heading">
        Relevant disciplinary history
    </h4>

    <table class="summary-table history-table">
        <thead>
            <tr>
                <th class="date-column">Date</th>
                <th>Previous offence or charge</th>
                <th class="sanction-column">Sanction</th>
            </tr>
        </thead>

        <tbody>
            {% for row in history_rows %}
                <tr>
                    <td class="date-column">
                        {% if row.date %}
                            {{ frappe.utils.formatdate(
                                row.date,
                                "dd MMMM yyyy"
                            ) }}
                        {% endif %}
                    </td>

                    <td class="preserve-lines">
                        {{ row.charges or "" }}
                    </td>

                    <td class="sanction-column">
                        {{ row.sanction or "" }}
                    </td>
                </tr>
            {% endfor %}
        </tbody>
    </table>
{% endif %}


{# ============================================================
   PENDING AND CANCELLED DISCIPLINARY ACTIONS

   These records are displayed for context only. They do not
   increase the occurrence level used for sanction calculation.
   ============================================================ #}

{% set untracked_rows = [] %}

{% if doc.accused %}
    {% set other_actions = frappe.get_all(
        "Disciplinary Action",
        filters={
            "accused": doc.accused,
            "name": ["!=", doc.name]
        },
        fields=[
            "name",
            "request_date",
            "outcome_date",
            "outcome",
            "modified"
        ],
        order_by="outcome_date desc, modified desc"
    ) %}

    {% for action in other_actions %}
        {% set action_status = namespace(
            include=false,
            label="",
            sanction=""
        ) %}

        {% if not action.outcome %}
            {% set action_status.include = true %}
            {% set action_status.label = "Pending" %}
            {% set action_status.sanction = "Pending" %}
        {% else %}
            {% set action_outcome_details = frappe.db.get_value(
                "Offence Outcome",
                action.outcome,
                [
                    "disc_offence_out",
                    "iscancellation"
                ],
                as_dict=True
            ) or {} %}

            {% set displayed_outcome =
                action_outcome_details.disc_offence_out
                or action.outcome
                or ""
            %}

            {% if action_outcome_details.iscancellation
                or (action.outcome | lower) == "cancelled"
                or (displayed_outcome | lower) == "cancelled"
            %}
                {% set action_status.include = true %}
                {% set action_status.label = "Cancelled" %}
                {% set action_status.sanction =
                    displayed_outcome or "Cancelled"
                %}
            {% endif %}
        {% endif %}

        {% if action_status.include %}
            {% set action_charges = frappe.get_all(
                "Disciplinary Charges",
                filters={
                    "parent": action.name,
                    "parenttype": "Disciplinary Action",
                    "parentfield": "final_charges"
                },
                fields=[
                    "idx",
                    "code_item",
                    "charge"
                ],
                order_by="idx asc"
            ) %}

            {% set charge_text = namespace(value="") %}

            {% for charge in action_charges %}
                {% set formatted_charge =
                    "(" ~ (charge.code_item or "") ~ ") "
                    ~ (charge.charge or "")
                %}

                {% if charge_text.value %}
                    {% set charge_text.value =
                        charge_text.value ~ "\n" ~ formatted_charge
                    %}
                {% else %}
                    {% set charge_text.value = formatted_charge %}
                {% endif %}
            {% endfor %}

            {% set action_date =
                action.outcome_date
                or action.request_date
                or action.modified
            %}

            {% set untracked_row = {
                "name": action.name,
                "date": action_date,
                "status": action_status.label,
                "outcome": action_status.sanction,
                "charges": charge_text.value
            } %}

            {% set _ = untracked_rows.append(untracked_row) %}
        {% endif %}
    {% endfor %}
{% endif %}


{% if untracked_rows %}
    <h4 class="section-heading">
        Pending and cancelled disciplinary actions
    </h4>

    <div class="history-information-note">
        These matters are displayed for context only. They are not treated as
        previous disciplinary outcomes and do not increase the occurrence
        level used to calculate the applicable sanction guideline.
    </div>

    <table class="summary-table untracked-history-table">
        <thead>
            <tr>
                <th class="status-column">Status</th>
                <th class="action-column">Action</th>
                <th class="date-column">Date</th>
                <th class="sanction-column">Recorded outcome</th>
                <th>Charge(s)</th>
            </tr>
        </thead>

        <tbody>
            {% for row in untracked_rows %}
                <tr>
                    <td class="status-column">
                        {% if row.status == "Pending" %}
                            <span class="history-status history-status-pending">
                                Pending
                            </span>
                        {% else %}
                            <span class="history-status history-status-cancelled">
                                Cancelled
                            </span>
                        {% endif %}
                    </td>

                    <td class="action-column">
                        {{ row.name }}
                    </td>

                    <td class="date-column">
                        {% if row.date %}
                            {{ frappe.utils.formatdate(
                                row.date,
                                "dd MMMM yyyy"
                            ) }}
                        {% endif %}
                    </td>

                    <td class="sanction-column">
                        {{ row.outcome or row.status }}
                    </td>

                    <td class="preserve-lines">
                        {% if row.charges %}
                            {{ row.charges }}
                        {% else %}
                            <span class="empty-inline">
                                No charges recorded.
                            </span>
                        {% endif %}
                    </td>
                </tr>
            {% endfor %}
        </tbody>
    </table>
{% endif %}


{# ============================================================
   SUPPORTING DOCUMENTS
   ============================================================ #}

{% if doc.attach %}
    <h4 class="section-heading">
        Supporting material attached
    </h4>

    <table class="summary-table">
        <thead>
            <tr>
                <th class="number-column">No.</th>
                <th>Attachment</th>
            </tr>
        </thead>

        <tbody>
            {% for row in doc.attach %}
                <tr>
                    <td class="number-column">
                        {{ row.idx }}
                    </td>

                    <td>
                        {% if row.attachment %}
                            {{ row.attachment }}
                        {% elif row.file %}
                            {{ row.file }}
                        {% elif row.file_url %}
                            {{ row.file_url }}
                        {% else %}
                            Supporting attachment {{ row.idx }}
                        {% endif %}
                    </td>
                </tr>
            {% endfor %}
        </tbody>
    </table>
{% endif %}


{# ============================================================
   CONFIRMATION
   ============================================================ #}

<h4 class="section-heading">
    Confirmation by initiator
</h4>

<div class="confirmation-text">
    <p>
        I confirm that I have reviewed this summary and that, to the
        best of my knowledge, the employee details, reported incident
        details and proposed charges recorded above are complete and
        accurate.
    </p>

    <p>
        I understand that the sanction guideline shown in this
        document is indicative only and does not constitute a finding
        or predetermined outcome.
    </p>

    <p>
        I request that the matter proceed to the next appropriate step
        in accordance with the Company’s disciplinary policy and
        procedure.
    </p>
</div>

<div class="decision-boxes">
    <table>
        <tbody>
            <tr>
                <td class="check-cell">□</td>

                <td>
                    Proceed with the disciplinary action request.
                </td>
            </tr>

            <tr>
                <td class="check-cell">□</td>

                <td>
                    Return the request for correction or further
                    information.
                </td>
            </tr>

            <tr>
                <td class="check-cell">□</td>

                <td>
                    Withdraw the request at this stage.
                </td>
            </tr>
        </tbody>
    </table>
</div>

<div class="comments-box">
    <div class="comments-label">
        Comments, corrections or additional instructions
    </div>

    <div class="writing-line"></div>
    <div class="writing-line"></div>
    <div class="writing-line"></div>
</div>


{# ============================================================
   SIGNATURES
   ============================================================ #}

<div class="signatures">
    <table>
        <tbody>
            <tr>
                <td class="signature-cell">
                    <div class="signature-line"></div>

                    <div class="signature-label">
                        {{ doc.compl_name
                            or "Person initiating disciplinary action"
                        }}
                        — Signature
                    </div>
                </td>

                <td class="date-cell">
                    <div class="signature-line"></div>

                    <div class="signature-label">
                        Date
                    </div>
                </td>
            </tr>

            <tr>
                <td class="signature-cell">
                    <div class="signature-line"></div>

                    <div class="signature-label">
                        {{ doc.responsible_ir_name
                            or "Responsible IR representative"
                        }}
                        — Signature
                    </div>
                </td>

                <td class="date-cell">
                    <div class="signature-line"></div>

                    <div class="signature-label">
                        Date
                    </div>
                </td>
            </tr>
        </tbody>
    </table>
</div>"}]
